body {
    background-color: var(--bg-main, #F5FEFF);
    color: var(--text-primary);
}

/* ----------------------------------------------------
   Website Profil Desa Wisata "Nepal van Java"
   Pages Stylesheet (pages.css)
   - Specific designs for individual pages / sections
   ---------------------------------------------------- */

/* ====================================================
   1. LANDING PAGE (index.html) - Hero Section (Revisited)
   ==================================================== */
/* ====================================================
   1. CINEMATIC HERO SECTION
   ==================================================== */
.cinematic-hero {
    position: relative;
    height: 100vh;
    width: 100%;
    display: flex;
    align-items: center;
    justify-content: center;
    padding-bottom: 0;
    overflow: hidden;
    background: url('../images/hero-bg.jpg') center/cover no-repeat;
}

.hero-image-overlay {
    position: absolute;
    inset: 0;
    /* Soft top dark overlay to expose navbar, merging into pure light blue-white background color (--bg-main = #F5FEFF) */
    background: linear-gradient(180deg,
            rgba(14, 47, 118, 0.45) 0%,
            rgba(14, 47, 118, 0.2) 40%,
            rgba(245, 254, 255, 0.1) 60%,
            rgba(245, 254, 255, 0.8) 85%,
            var(--bg-main, #F5FEFF) 100%);
    z-index: 1;
}

.cinematic-hero-content {
    position: relative;
    z-index: 3;
    display: flex;
    flex-direction: column;
    align-items: center;
    text-align: center;
    gap: 1.5rem;
    max-width: 900px;
    margin: 0 auto;
    width: 100%;
    padding: 0 2rem;
    margin-bottom: 0;
}

.cinematic-hero .hero-title {
    font-family: var(--font-primary);
    font-size: clamp(2.2rem, 5vw, 4.5rem);
    font-weight: 800;
    line-height: 1.15;
    letter-spacing: -0.03em;
    color: var(--text-primary, #0E2F76);
    text-shadow: 0 2px 20px rgba(255, 255, 255, 0.8), 0 0 40px rgba(255, 255, 255, 0.4);
    animation: fadeInUp 1s cubic-bezier(0.16, 1, 0.3, 1) both;
}

.cinematic-hero .hero-subtitle {
    font-family: var(--font-primary);
    font-size: clamp(1rem, 1.8vw, 1.25rem);
    font-weight: 600;
    color: var(--text-primary, #0E2F76);
    line-height: 1.7;
    max-width: 700px;
    text-shadow: 0 2px 20px rgba(255, 255, 255, 0.8);
    margin-bottom: 0;
    animation: fadeInUp 1s cubic-bezier(0.16, 1, 0.3, 1) 0.2s both;
}

.cinematic-hero .hero-tagline {
    font-size: 0.85rem;
    font-weight: 700;
    letter-spacing: 3px;
    text-transform: uppercase;
    color: var(--text-primary, #0E2F76);
    background-color: rgba(255, 255, 255, 0.5);
    padding: 6px 16px;
    border-radius: 50px;
    backdrop-filter: blur(8px);
    -webkit-backdrop-filter: blur(8px);
    border: 1px solid rgba(14, 47, 118, 0.1);
    animation: fadeInUp 1s cubic-bezier(0.16, 1, 0.3, 1) 0.1s both;
}

/* ====================================================
   2. STICKY STORY SECTION
   ==================================================== */
.sticky-story-section {
    padding: 12rem 2rem;
    background-color: var(--bg-main, #F5FEFF);
    position: relative;
    z-index: 2;
}

.story-grid {
    display: grid;
    grid-template-columns: 1.25fr 0.75fr;
    gap: 5rem;
    max-width: 1200px;
    margin: 0 auto;
    align-items: start;
}

.story-text-col {
    display: flex;
    flex-direction: column;
    gap: 2rem;
    text-align: left;
}

.story-tagline {
    font-size: 0.85rem;
    font-weight: 700;
    letter-spacing: 3px;
    text-transform: uppercase;
    color: var(--bg-accent, #AAC0E1);
}

.story-title {
    font-size: clamp(2rem, 4.5vw, 3.5rem);
    font-weight: 800;
    color: var(--text-primary, #0E2F76);
    line-height: 1.15;
    margin-bottom: 0.5rem;
}

.story-p {
    font-size: 1.125rem;
    line-height: 1.8;
    color: var(--text-primary, #0E2F76);
    opacity: 0.85;
    margin: 0;
}

.story-image-col {
    position: relative;
}

.sticky-image-wrapper {
    position: sticky;
    top: 120px;
    border-radius: 16px;
    overflow: hidden;
    border: 8px solid #ffffff;
    box-shadow: 0 30px 60px rgba(14, 47, 118, 0.08);
}

.story-portrait-img {
    width: 100%;
    height: 550px;
    object-fit: cover;
    display: block;
}

/* ====================================================
   3. FLOATING BENTO SECTION
   ==================================================== */
.floating-bento-section {
    padding: 12rem 2rem;
    background-color: var(--bg-main, #F5FEFF);
    position: relative;
    z-index: 2;
}

.bento-header {
    text-align: center;
    margin-bottom: 5rem;
}

.bento-tagline {
    font-size: 0.85rem;
    font-weight: 700;
    letter-spacing: 3px;
    text-transform: uppercase;
    color: var(--bg-accent, #AAC0E1);
    display: block;
    margin-bottom: 1rem;
}

.bento-section-title {
    font-size: clamp(2rem, 4vw, 3rem);
    font-weight: 800;
    color: var(--text-primary, #0E2F76);
}

.bento-grid {
    display: grid;
    grid-template-columns: 1.4fr 1fr 1fr;
    grid-auto-rows: 320px;
    gap: 2.5rem;
    max-width: 1200px;
    margin: 0 auto;
}

.bento-card-large {
    grid-column: span 2;
    grid-row: span 2;
}

.bento-card-medium {
    grid-column: span 1;
    grid-row: span 1;
}

.bento-card-tall {
    grid-column: span 1;
    grid-row: span 1;
}

.bento-card {
    position: relative;
    border-radius: 16px;
    overflow: hidden;
    box-shadow: 0 20px 40px rgba(14, 47, 118, 0.05);
    cursor: pointer;
    height: 100%;
    transition: all 0.6s cubic-bezier(0.16, 1, 0.3, 1);
}

.bento-card:hover {
    transform: translateY(-8px);
    box-shadow: 0 30px 60px rgba(14, 47, 118, 0.12);
}

.bento-img {
    width: 100%;
    height: 100%;
    object-fit: cover;
    display: block;
    transition: all 0.6s cubic-bezier(0.16, 1, 0.3, 1);
}

.bento-card:hover .bento-img {
    transform: scale(1.08);
}

.bento-overlay-glass {
    position: absolute;
    inset: 0;
    background: rgba(0, 0, 0, 0.7);
    backdrop-filter: blur(12px);
    -webkit-backdrop-filter: blur(12px);
    display: flex;
    flex-direction: column;
    justify-content: flex-end;
    padding: 2.5rem;
    border-top: 1px solid rgba(255, 255, 255, 0.15);
    opacity: 0;
    transform: translateY(100%);
    transition: all 0.6s cubic-bezier(0.16, 1, 0.3, 1);
    z-index: 2;
}

.bento-card:hover .bento-overlay-glass {
    opacity: 1;
    transform: translateY(0);
}

.bento-card-title {
    font-size: clamp(1.3rem, 2.5vw, 1.8rem);
    font-weight: 700;
    color: #ffffff;
    margin-bottom: 0.75rem;
    text-shadow: 0 2px 10px rgba(0, 0, 0, 0.2);
}

.bento-card-title .rolling-link {
    color: #ffffff;
    display: inline-block;
    width: 100%;
}

.bento-card-title .rolling-text-front {
    color: #ffffff;
}

.bento-card-title .rolling-text-back {
    color: #75E6A4;
    /* Light accent mint green */
}

/* Trigger rolling text inside Bento Card on card hover */
.bento-card:hover .bento-card-title .rolling-text-wrap {
    transform: translateY(-100%);
}

.bento-card:hover .bento-card-title .rolling-text-front {
    opacity: 0;
}

.bento-card-desc {
    font-size: 0.95rem;
    line-height: 1.6;
    color: rgba(255, 255, 255, 0.85);
    margin-bottom: 1.5rem;
}

.bento-card-link {
    font-size: 0.85rem;
    font-weight: 700;
    color: var(--bg-accent, #AAC0E1);
    align-self: flex-start;
    display: inline-flex;
    align-items: center;
    gap: 0.25rem;
    transition: color 0.3s ease;
}

.bento-card-link:hover {
    color: #ffffff;
}

/* ====================================================
   4. IMPACT & CTA SECTION
   ==================================================== */
.impact-cta-section {
    position: relative;
    padding: 12rem 2rem;
    background: linear-gradient(135deg, #091E4A 0%, #0E2F76 50%, #174EBE 100%);
    color: #ffffff;
    overflow: hidden;
    z-index: 2;
}

.impact-overlay {
    position: absolute;
    inset: 0;
    background: radial-gradient(circle at center, rgba(23, 78, 190, 0.18) 0%, transparent 75%);
    pointer-events: none;
}

.impact-container {
    position: relative;
    z-index: 3;
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 6rem;
    max-width: 1200px;
    margin: 0 auto;
}

.impact-stats-grid {
    display: grid;
    grid-template-columns: repeat(3, 1fr);
    gap: 4rem;
    width: 100%;
    max-width: 900px;
    text-align: center;
}

.impact-stat-card {
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 0.75rem;
}

.impact-stat-number {
    font-size: clamp(3rem, 6vw, 5rem);
    font-weight: 800;
    color: #ffffff;
    line-height: 1;
    text-shadow: 0 0 30px rgba(255, 255, 255, 0.25);
    font-family: var(--font-primary);
}

.impact-stat-label {
    font-size: 0.85rem;
    font-weight: 700;
    text-transform: uppercase;
    letter-spacing: 2px;
    color: var(--bg-accent, #AAC0E1);
}

.impact-cta-content {
    text-align: center;
    max-width: 700px;
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 2rem;
}

