{"content":"/* ----------------------------------------------------
   Website Profil Desa Wisata "Nepal van Java"
   Layout Stylesheet (layout.css)
   - Global Container
   - Main Header & Navbar (Biru Tua-Putih)
   - Dropdown Menu
   - Responsive Mobile Navigation
   - Main Footer (Biru Tua/Muda)
   ---------------------------------------------------- */

/* Container Setup */
.container {
    width: 100%;
    max-width: 1200px;
    margin-left: auto;
    margin-right: auto;
    padding-left: var(--space-md);
    padding-right: var(--space-md);
}

/* ============================================
   NAVBAR / HEADER — Premium Light Glassmorphism
   ============================================ */
#main-header {
    position: fixed;
    top: 0;
    left: 0; 
    right: 0;
    width: 92%;
    max-width: 1200px;
    margin: 20px auto;
    z-index: 1000;
    padding: 12px 0;
    border-radius: 20px;
    transition: all 0.5s cubic-bezier(0.16, 1, 0.3, 1);

    /* Premium Shiny & Perfectly Transparent Glassmorphism */
    background: linear-gradient(
        135deg,
        rgba(255, 255, 255, 0.2) 0%,
        rgba(255, 255, 255, 0.05) 50%,
        rgba(255, 255, 255, 0.15) 100%
    );
    backdrop-filter: blur(25px);
    -webkit-backdrop-filter: blur(25px);
    box-shadow: 
        0 12px 32px 0 rgba(14, 47, 118, 0.06), 
        inset 0 1px 0 rgba(255, 255, 255, 0.35),
        inset 0 -1px 0 rgba(255, 255, 255, 0.1);
    border: 1px solid rgba(255, 255, 255, 0.4);
    color: #FFFFFF;
}

/* Scrolled State: adjust padding, margin and background opacity slightly */
#main-header.header-scrolled {
    padding: 8px 0;
    margin: 10px auto;
    background: linear-gradient(
        135deg,
        rgba(255, 255, 255, 0.25) 0%,
        rgba(255, 255, 255, 0.08) 50%,
        rgba(255, 255, 255, 0.22) 100%
    );
    box-shadow: 
        0 16px 40px 0 rgba(14, 47, 118, 0.1), 
        inset 0 1px 0 rgba(255, 255, 255, 0.4);
    border-color: rgba(255, 255, 255, 0.45);
    color: #0E2F76;
}

/* Maintain .nav-adapt to slightly increase opacity when scrolling */
#main-header.nav-adapt {
    background: linear-gradient(
        135deg,
        rgba(255, 255, 255, 0.28) 0%,
        rgba(255, 255, 255, 0.1) 50%,
        rgba(255, 255, 255, 0.25) 100%
    );
}

/* Nav Container Layout */
.nav-container {
    display: flex;
    justify-content: space-between;
    align-items: center;
    max-width: 1200px;
    margin: 0 auto;
    padding: 0 2rem;
}

/* Logo Styling */
.logo {
    font-size: 1.5rem;
    font-weight: 800;
    letter-spacing: -0.5px;
    color: inherit;
    display: flex;
    align-items: center;
    text-decoration: none;
    flex-shrink: 0;
}

.logo-accent {
    color: inherit;
    margin-right: 4px;
}

/* Navigation Menu */
.nav-menu {
    display: flex;
    align-items: center;
    list-style: none;
    gap: 4px;
    margin: 0;
    padding: 0;
}

.nav-item {
    position: relative;
}

.nav-link {
    color: inherit;
    font-weight: 600;
    font-size: 0.95rem;
    padding: 0 16px;
    height: 38px;
    display: inline-flex;
    align-items: center;
    text-decoration: none;
    transition: all 0.3s ease;
    border-radius: 50px;
    white-space: nowrap;
    overflow: hidden;
    position: relative;
}

/* Rolling Text Animation on Hover */
.rolling-link {
    display: inline-block;
    overflow: hidden;
    text-decoration: none;
    vertical-align: top;
    position: relative;
}

.rolling-text-wrap {
    display: block;
    position: relative;
    transition: transform 0.4s cubic-bezier(0.16, 1, 0.3, 1);
}

.rolling-text-front {
    display: block;
    transition: opacity 0.4s ease;
    color: inherit;
}

.rolling-text-back {
    display: block;
    position: absolute;
    top: 100%;
    left: 0;
    width: 100%;
    text-align: inherit;
    font-weight: 750;
    color: inherit;
}

/* Default State (Hero Section - Unscrolled) */
#main-header:not(.header-scrolled) .nav-link .rolling-text-front {
    color: #FFFFFF;
}

#main-header:not(.header-scrolled) .nav-link .rolling-text-back {
    color: #0E2F76;
}

#main-header:not(.header-scrolled) .nav-link:hover,
#main-header:not(.header-scrolled) .nav-link.active {
    background-color: rgba(255, 255, 255, 0.95);
    box-shadow: 0 4px 12px rgba(14, 47, 118, 0.08);
}

/* Scrolled State */
#main-header.header-scrolled .nav-link .rolling-text-front {
    color: #0E2F76;
}

#main-header.header-scrolled .nav-link .rolling-text-back {
    color: #FFFFFF;
}

#main-header.header-scrolled .nav-link:hover,
#main-header.header-scrolled .nav-link.active {
    background-color: #0E2F76;
    box-shadow: 0 4px 12px rgba(14, 47, 118, 0.15);
}

/* Specific styling for navbar links to align with height 38px */
.nav-link.rolling-link {
    display: inline-flex;
    align-items: center;
}

.nav-link .rolling-text-wrap {
    height: 38px;
}

.nav-link .rolling-text-front,
.nav-link .rolling-text-back {
    height: 38px;
    display: flex;
    align-items: center;
    line-height: 38px;
}

/* Hover Trigger (Efek Bergulir) */
.rolling-link:hover .rolling-text-wrap,
.rolling-link.active .rolling-text-wrap {
    transform: translateY(-100%);
}

.rolling-link:hover .rolling-text-front,
.rolling-link.active .rolling-text-front {
    opacity: 0;
}

/* Dropdown Icon Rotation */
.dropdown-icon {
    transition: transform var(--transition-fast);
}

.dropdown:hover .dropdown-icon,
.dropdown:focus-within .dropdown-icon {
    transform: rotate(180deg);
}

/* Dropdown Menu Styles (Desktop) - Penyempurnaan Premium */
.dropdown-menu {
    position: absolute;
    top: 100%;
    left: 50%;
    transform: translateX(-50%) translateY(15px);
    background-color: rgba(255, 255, 255, 0.95);
    backdrop-filter: blur(10px);
    border-top: 3px solid #0E2F76;
    min-width: 200px;
    box-shadow: var(--shadow-lg);
    border-radius: 0 0 var(--radius-md) var(--radius-md);"}

{"content":"@import url('https://fonts.googleapis.com/css2?family=Plus+Jakarta+Sans:wght@300;400;500;600;700;800&display=swap');

/* ----------------------------------------------------
   Website Profil Desa Wisata "Nepal van Java"
   Base Stylesheet (base.css)
   - Santorini Color Palette Variables
   - Typography Settings
   - CSS Reset
   ---------------------------------------------------- */

/* Google Fonts loaded via HTML <link> tags */

:root {
    /* Color Palette - Santorini Theme */
    --bg-main: #F5FEFF;         /* Latar belakang bersih / langit */
    --bg-accent: #AAC0E1;       /* Overlay lembut / area sekunder */
    --text-primary: #0E2F76;    /* Teks judul/utama, warna latar belakang header */
    --text-secondary: #FFFFFF;  /* Teks kontras pada latar belakang biru tua */
    --color-cta: #0E2F76;       /* Warna tombol utama (Call to Action) */

    /* Additional Harmonious Accent Colors for Premium Feel */
    --color-accent-light: #EBF8FF; /* Soft background tint for cards/sections */
    --color-accent-dark: #071D4A;  /* Deep navy for footer, dark text or hover states */
    --color-gold: #D4AF37;         /* Warm sun gold for ratings and highlights */
    --color-gray: #5A7184;         /* Muted gray for readable body/description text */

    /* Typography Fonts */
    --font-primary: 'Plus Jakarta Sans', sans-serif;

    /* Spacing Tokens */
    --space-xs: 0.25rem;
    --space-sm: 0.5rem;
    --space-md: 1rem;
    --space-lg: 1.5rem;
    --space-xl: 2.5rem;
    --space-xxl: 4rem;

    /* Design Tokens */
    --radius-sm: 6px;
    --radius-md: 12px;
    --radius-lg: 24px;
    --radius-full: 9999px;

    /* Transitions */
    --transition-fast: 0.2s cubic-bezier(0.16, 1, 0.3, 1);
    --transition-normal: 0.3s cubic-bezier(0.16, 1, 0.3, 1);

    /* Box Shadows */
    --shadow-sm: 0 2px 8px rgba(14, 47, 118, 0.04);
    --shadow-md: 0 8px 24px rgba(14, 47, 118, 0.08);
    --shadow-lg: 0 16px 48px rgba(14, 47, 118, 0.12);
}

/* Modern CSS Reset */
*, *::before, *::after {
    box-sizing: border-box;
    margin: 0;
    padding: 0;
}

/* Base Document Configuration */
html {
    scroll-behavior: smooth;
    font-size: 16px;
    -webkit-text-size-adjust: 100%;
}

body {
    font-family: var(--font-primary);
    background-color: var(--bg-main);
    color: var(--text-primary);
    line-height: 1.6;
    font-weight: 400;
    min-height: 100vh;
    overflow-x: hidden;
    -webkit-font-smoothing: antialiased;
    -moz-osx-font-smoothing: grayscale;
}

/* Typography Defaults */
h1, h2, h3, h4, h5, h6, p, .judul-utama {
    font-family: var(--font-primary);
}

h1, .judul-utama {
    font-size: clamp(2.5rem, 5vw, 4.5rem);
    font-weight: 800;
    letter-spacing: -0.03em;
    line-height: 1.1;
    color: var(--text-primary);
    margin-bottom: var(--space-sm);
}

h2 {
    font-size: clamp(2rem, 4vw, 3rem);
    font-weight: 700;
    letter-spacing: -0.02em;
    line-height: 1.2;
    color: var(--text-primary);
    margin-bottom: var(--space-sm);
}

h3 {
    font-size: 1.5rem;
    font-weight: 600;
    line-height: 1.4;
    color: var(--text-primary);
    margin-bottom: var(--space-sm);
}

p {
    font-size: 1.125rem;
    font-weight: 400;
    line-height: 1.7;
    color: var(--text-primary);
    margin-bottom: var(--space-md);
}

/* Link Reset & Base Behavior */
a {
    color: inherit;
    text-decoration: none;
    transition: color var(--transition-fast), background-color var(--transition-fast);
}

/* Image Reset */
img, picture, video, canvas, svg {
    display: block;
    max-width: 100%;
    height: auto;
}

/* Form Elements Reset */
input, button, textarea, select {
    font: inherit;
    color: inherit;
}

button {
    background: none;
    border: none;
    cursor: pointer;
}
