    /* ============================================================
       6. ANIMATED COUNTER (Impact Stats)
       Menghitung angka dari 0 ke target saat section terlihat.
       Elemen harus punya: data-count-target, data-count-suffix (opsional)
       ============================================================ */
    /**
     * Animasikan sebuah elemen counter dari 0 ke targetnya.
     * @param {HTMLElement} el - Elemen span angka
     */
    function animateCounter(el) {
        const target = parseInt(el.getAttribute('data-count-target'), 10);
        const suffix = el.getAttribute('data-count-suffix') || '';
        const prefix = el.getAttribute('data-count-prefix') || '';
        const duration = 1800; // ms
        const startTime = performance.now();

        function tick(now) {
            const elapsed = now - startTime;
            const progress = Math.min(elapsed / duration, 1);
            // Easing: ease-out cubic
            const eased = 1 - Math.pow(1 - progress, 3);
            const current = Math.round(eased * target);
            el.textContent = prefix + current.toLocaleString('id-ID') + suffix;
            if (progress < 1) {
                requestAnimationFrame(tick);
            }
        }
        requestAnimationFrame(tick);
    }

    // Observasi semua elemen counter, jalankan animasi satu kali saat masuk viewport
    const counterObserver = new IntersectionObserver((entries, obs) => {
        entries.forEach(entry => {
            if (entry.isIntersecting) {
                animateCounter(entry.target);
                obs.unobserve(entry.target);
            }
        });
    }, { threshold: 0.5 });

    document.querySelectorAll('[data-count-target]').forEach(el => {
        counterObserver.observe(el);
    });
});
